using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Pages;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Components;
using ShipmentTracker.Components.Account;
using ShipmentTracker.Data;
using ShipmentTracker.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents()
    .AddInteractiveWebAssemblyComponents()
    .AddAuthenticationStateSerialization(options => options.SerializeAllClaims = true);

builder.Services.AddCascadingAuthenticationState();
builder.Services.AddScoped<IdentityRedirectManager>();
builder.Services.AddScoped<AuthenticationStateProvider, IdentityRevalidatingAuthenticationStateProvider>();

builder.Services.AddAuthentication(options =>
    {
        options.DefaultScheme = IdentityConstants.ApplicationScheme;
        options.DefaultSignInScheme = IdentityConstants.ExternalScheme;
    })
    .AddIdentityCookies();

builder.Services.AddAuthorizationBuilder()
    .AddPolicy("DispatcherOnly", policy => policy.RequireRole("Dispatcher"));

var connectionString = builder.Configuration.GetConnectionString("DefaultConnection") ?? throw new InvalidOperationException("Connection string 'DefaultConnection' not found.");
builder.Services.AddDbContext<ApplicationDbContext>(options =>
    options.UseSqlite(connectionString));
builder.Services.AddDatabaseDeveloperPageExceptionFilter();

builder.Services.AddIdentityCore<ApplicationUser>(options =>
    {
        options.SignIn.RequireConfirmedAccount = true;
        options.Stores.SchemaVersion = IdentitySchemaVersions.Version3;
    })
    .AddRoles<IdentityRole>()
    .AddEntityFrameworkStores<ApplicationDbContext>()
    .AddSignInManager()
    .AddDefaultTokenProviders();

builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();
builder.Services.AddScoped<ServerShipmentService>();
builder.Services.AddScoped<IShipmentService>(sp => sp.GetRequiredService<ServerShipmentService>());

var app = builder.Build();

// Seed data
using (var scope = app.Services.CreateScope())
{
    var services = scope.ServiceProvider;
    var db = services.GetRequiredService<ApplicationDbContext>();
    await db.Database.MigrateAsync();

    var roleManager = services.GetRequiredService<RoleManager<IdentityRole>>();
    var userManager = services.GetRequiredService<UserManager<ApplicationUser>>();

    string[] roles = ["Dispatcher", "Customer"];
    foreach (var role in roles)
    {
        if (!await roleManager.RoleExistsAsync(role))
            await roleManager.CreateAsync(new IdentityRole(role));
    }

    var dispatcher = await userManager.FindByEmailAsync("dispatcher@shiptrack.com");
    if (dispatcher == null)
    {
        dispatcher = new ApplicationUser
        {
            UserName = "dispatcher@shiptrack.com",
            Email = "dispatcher@shiptrack.com",
            EmailConfirmed = true
        };
        await userManager.CreateAsync(dispatcher, "Pass123!");
        await userManager.AddToRoleAsync(dispatcher, "Dispatcher");
    }

    var customer = await userManager.FindByEmailAsync("customer@shiptrack.com");
    if (customer == null)
    {
        customer = new ApplicationUser
        {
            UserName = "customer@shiptrack.com",
            Email = "customer@shiptrack.com",
            EmailConfirmed = true
        };
        await userManager.CreateAsync(customer, "Pass123!");
        await userManager.AddToRoleAsync(customer, "Customer");
    }

    if (!db.Shipments.Any())
    {
        var shipments = new List<Shipment>
        {
            new() { TrackingNumber = "ST-20250101-AAAA1111", Origin = "New York, NY", Destination = "Los Angeles, CA", Status = ShipmentStatus.InTransit, EstimatedDelivery = DateTimeOffset.UtcNow.AddDays(3), CreatedAt = DateTimeOffset.UtcNow.AddDays(-2), CustomerId = customer.Id },
            new() { TrackingNumber = "ST-20250102-BBBB2222", Origin = "Chicago, IL", Destination = "Houston, TX", Status = ShipmentStatus.Pending, EstimatedDelivery = DateTimeOffset.UtcNow.AddDays(5), CreatedAt = DateTimeOffset.UtcNow.AddDays(-1), CustomerId = customer.Id },
            new() { TrackingNumber = "ST-20250103-CCCC3333", Origin = "Seattle, WA", Destination = "Denver, CO", Status = ShipmentStatus.OutForDelivery, EstimatedDelivery = DateTimeOffset.UtcNow, CreatedAt = DateTimeOffset.UtcNow.AddDays(-4), CustomerId = customer.Id },
            new() { TrackingNumber = "ST-20250104-DDDD4444", Origin = "Miami, FL", Destination = "Atlanta, GA", Status = ShipmentStatus.Delivered, EstimatedDelivery = DateTimeOffset.UtcNow.AddDays(-1), CreatedAt = DateTimeOffset.UtcNow.AddDays(-5), CustomerId = customer.Id },
            new() { TrackingNumber = "ST-20250105-EEEE5555", Origin = "Boston, MA", Destination = "Philadelphia, PA", Status = ShipmentStatus.Delayed, EstimatedDelivery = DateTimeOffset.UtcNow.AddDays(2), CreatedAt = DateTimeOffset.UtcNow.AddDays(-3), CustomerId = customer.Id },
        };
        db.Shipments.AddRange(shipments);
        await db.SaveChangesAsync();
    }
}

// Configure the HTTP request pipeline.
if (app.Environment.IsDevelopment())
{
    app.UseWebAssemblyDebugging();
    app.UseMigrationsEndPoint();
}
else
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
app.UseAntiforgery();

// API Endpoints
var api = app.MapGroup("/api/shipments");

api.MapGet("/", async (ServerShipmentService service) =>
{
    var shipments = await service.GetAllShipmentsAsync();
    return Results.Ok(shipments);
}).RequireAuthorization("DispatcherOnly");

api.MapGet("/my", async (HttpContext context, ServerShipmentService service) =>
{
    var userId = context.User.FindFirst(System.Security.Claims.ClaimTypes.NameIdentifier)?.Value;
    if (userId is null) return Results.Unauthorized();
    var shipments = await service.GetShipmentsForUserAsync(userId);
    return Results.Ok(shipments);
}).RequireAuthorization();

api.MapGet("/track/{trackingNumber}", async (string trackingNumber, ServerShipmentService service) =>
{
    var shipment = await service.GetByTrackingNumberAsync(trackingNumber);
    return shipment is null ? Results.NotFound() : Results.Ok(shipment);
}).AllowAnonymous();

api.MapPost("/", async (CreateShipmentDto dto, ServerShipmentService service) =>
{
    var shipment = await service.CreateShipmentAsync(dto);
    return Results.Created($"/api/shipments/track/{shipment.TrackingNumber}", shipment);
}).RequireAuthorization("DispatcherOnly");

api.MapPut("/{id}/status", async (int id, StatusUpdateRequest request, ServerShipmentService service) =>
{
    await service.UpdateStatusAsync(id, request.Status);
    return Results.NoContent();
}).RequireAuthorization("DispatcherOnly");

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveServerRenderMode()
    .AddInteractiveWebAssemblyRenderMode()
    .AddAdditionalAssemblies(typeof(ShipmentTracker.Client._Imports).Assembly);

// Add additional endpoints required by the Identity /Account Razor components.
app.MapAdditionalIdentityEndpoints();

app.Run();

record StatusUpdateRequest(string Status);

