@page "/"
@inject NavigationManager Navigation

<PageTitle>ShipmentTracker - Home</PageTitle>

<h1>Welcome to ShipmentTracker</h1>
<p class="lead">Track your shipments in real-time.</p>

<AuthorizeView Roles="Dispatcher">
    <Authorized>
        <div class="mb-3">
            <a href="dispatch" class="btn btn-primary">Go to Dispatch Dashboard</a>
        </div>
    </Authorized>
</AuthorizeView>

<AuthorizeView>
    <Authorized>
        <div class="mb-3">
            <a href="my-shipments" class="btn btn-outline-primary">My Shipments</a>
        </div>
    </Authorized>
</AuthorizeView>

<hr />

<h4>Track a Shipment</h4>
<div class="input-group mb-3" style="max-width: 500px;">
    <input type="text" class="form-control" placeholder="Enter tracking number" @bind="trackingNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
    <button class="btn btn-success" @onclick="TrackShipment" disabled="@string.IsNullOrWhiteSpace(trackingNumber)">Track</button>
</div>

@code {
    private string trackingNumber = "";

    private void TrackShipment()
    {
        if (!string.IsNullOrWhiteSpace(trackingNumber))
            Navigation.NavigateTo($"track/{trackingNumber.Trim()}");
    }

    private void HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            TrackShipment();
    }
}

