@page "/dispatch"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>Dispatch Dashboard</PageTitle>

<h2>Dispatch Dashboard</h2>

@if (loading)
{
    <p>Loading shipments...</p>
}
else
{
    <button class="btn btn-primary mb-3" @onclick="ToggleCreateForm">
        @(showCreateForm ? "Cancel" : "Create Shipment")
    </button>

    @if (showCreateForm)
    {
        <div class="card mb-4 p-3">
            <h5>New Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="Origin" @bind="newOrigin" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Destination" @bind="newDestination" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Customer Email" @bind="newCustomerEmail" />
                </div>
                <div class="col-md-2">
                    <input class="form-control" type="date" @bind="newEstimatedDelivery" />
                </div>
                <div class="col-md-1">
                    <button class="btn btn-success" @onclick="CreateShipment">Add</button>
                </div>
            </div>
            @if (!string.IsNullOrEmpty(createError))
            {
                <div class="text-danger mt-2">@createError</div>
            }
        </div>
    }

    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in shipments)
            {
                <tr>
                    <td><code>@shipment.TrackingNumber</code></td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                value="@shipment.Status"
                                @onchange="(e) => UpdateStatus(shipment.Id, e.Value?.ToString() ?? "")">
                            <option value="Pending">Pending</option>
                            <option value="InTransit">InTransit</option>
                            <option value="OutForDelivery">OutForDelivery</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Delayed">Delayed</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto> shipments = [];
    private bool loading = true;
    private bool showCreateForm;
    private string newOrigin = "";
    private string newDestination = "";
    private string newCustomerEmail = "";
    private DateTimeOffset? newEstimatedDelivery;
    private string? createError;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        shipments = await ShipmentService.GetAllShipmentsAsync();
        loading = false;
    }

    private void ToggleCreateForm() => showCreateForm = !showCreateForm;

    private async Task CreateShipment()
    {
        createError = null;
        try
        {
            var dto = new CreateShipmentDto(newOrigin, newDestination, newCustomerEmail, newEstimatedDelivery);
            await ShipmentService.CreateShipmentAsync(dto);
            newOrigin = "";
            newDestination = "";
            newCustomerEmail = "";
            newEstimatedDelivery = null;
            showCreateForm = false;
            await LoadShipments();
        }
        catch (Exception ex)
        {
            createError = ex.Message;
        }
    }

    private async Task UpdateStatus(int id, string status)
    {
        if (string.IsNullOrEmpty(status)) return;
        await ShipmentService.UpdateStatusAsync(id, status);
        await LoadShipments();
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "InTransit" => "bg-info text-dark",
        "OutForDelivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Delayed" => "bg-danger",
        _ => "bg-secondary"
    };
}

